INSERT INTO public.vocabulary_examples (id, vocab_id, japanese, reading, translation) VALUES
('ex_n3_auto_1726', 'v_n3_auto_1726', '彼はしきりに電話をかけてくる。', 'かれは しきりに でんわを かけてくる。', 'Dia terus-menerus meneleponku.'),
('ex_n3_auto_1727', 'v_n3_auto_1727', '彼はじっと目を閉じていた。', 'かれは じっと めを とじていた。', 'Dia memejamkan mata dengan tenang.'),
('ex_n3_auto_1728', 'v_n3_auto_1728', 'この道路ではしばしば事故が起こる。', 'この どうろでは しばしば じこが おこる。', 'Di jalan ini sering terjadi kecelakaan.'),
('ex_n3_auto_1729', 'v_n3_auto_1729', '授業中にしゃべらないでください。', 'じゅぎょうちゅうに しゃべらないで ください。', 'Tolong jangan mengobrol saat pelajaran.'),
('ex_n3_auto_1730', 'v_n3_auto_1730', 'このレモンはとてもすっぱい。', 'この れもんは とても すっぱい。', 'Lemon ini sangat asam.'),
('ex_n3_auto_1731', 'v_n3_auto_1731', 'すてきなプレゼントをありがとう。', 'すてきな プレゼントを ありがとう。', 'Terima kasih atas hadiah yang menakjubkan ini.'),
('ex_n3_auto_1732', 'v_n3_auto_1732', '予定の時間が少しずれた。', 'よていの じかんが すこし ずれた。', 'Waktu jadwalnya agak bergeser.'),
('ex_n3_auto_1733', 'v_n3_auto_1733', '京都のあちこちを観光した。', 'きょうとの あちこちを かんこうした。', 'Kami berwisata ke sana-sini di Kyoto.'),
('ex_n3_auto_1734', 'v_n3_auto_1734', 'あらゆる方法を試してみた。', 'あらゆる ほうほうを ためしてみた。', 'Aku sudah mencoba segala cara.'),
('ex_n3_auto_1735', 'v_n3_auto_1735', '手伝ってくれてありがとう。', 'てつだってくれて ありがとう。', 'Terima kasih sudah membantu.'),
('ex_n3_auto_1736', 'v_n3_auto_1736', 'あんなに高いビルは初めて見た。', 'あんなに たかい びるは はじめて みた。', 'Baru pertama kali ini aku melihat gedung setinggi itu.'),
('ex_n3_auto_1737', 'v_n3_auto_1737', '今日はあんまり寒くない。', 'きょうは あんまり さむくない。', 'Hari ini tidak terlalu dingin.'),
('ex_n3_auto_1738', 'v_n3_auto_1738', '嘘をついてはいけません。', 'うそを ついては いけません。', 'Tidak boleh berbohong.'),
('ex_n3_auto_1739', 'v_n3_auto_1739', '子どもがいたずらをして怒られた。', 'こどもが いたずらを して おこられた。', 'Anak itu dimarahi karena berbuat nakal.'),
('ex_n3_auto_1740', 'v_n3_auto_1740', 'ご飯を食べる前にいただきますと言う。', 'ごはんを たべる まえに いただきますと いう。', 'Sebelum makan kita mengucapkan selamat makan.'),
('ex_n3_auto_1741', 'v_n3_auto_1741', 'いつか日本へ行ってみたい。', 'いつか にほんへ いってみたい。', 'Suatu saat aku ingin mencoba pergi ke Jepang.'),
('ex_n3_auto_1742', 'v_n3_auto_1742', '外はいつのまにか雨が降っていた。', 'そとは いつのまにか あめが ふっていた。', 'Tanpa disadari di luar sudah turun hujan.'),
('ex_n3_auto_1743', 'v_n3_auto_1743', '私たちはいつまでも友達だ。', 'わたしたちは いつまでも ともだちだ。', 'Kita adalah teman selamanya.'),
('ex_n3_auto_1744', 'v_n3_auto_1744', '渋滞でいらいらする。', 'じゅうたいで いらいら する。', 'Aku merasa jengkel karena kemacetan.'),
('ex_n3_auto_1745', 'v_n3_auto_1745', 'ようこそ、我が家へいらっしゃい。', 'ようこそ、 わがやへ いらっしゃい。', 'Selamat datang di rumah kami.'),
('ex_n3_auto_1746', 'v_n3_auto_1746', '彼は、いわゆる天才だ。', 'かれは、 いわゆる てんさいだ。', 'Dia adalah orang yang biasa disebut jenius.'),
('ex_n3_auto_1747', 'v_n3_auto_1747', '帰宅したら手洗いとうがいをしよう。', 'きたくしたら てあらいと うがいを しよう。', 'Mari mencuci tangan dan berkumur setelah pulang ke rumah.'),
('ex_n3_auto_1748', 'v_n3_auto_1748', '犬が見知らぬ人に向かってうなっている。', 'いぬが みしらぬ ひとに むかって うなっている。', 'Anjing itu mengerang ke arah orang asing.'),
('ex_n3_auto_1749', 'v_n3_auto_1749', 'お誕生日おめでとうございます！', 'おたんじょうび おめでとう ございます！', 'Selamat hari ulang tahun!'),
('ex_n3_auto_1750', 'v_n3_auto_1750', '不合格と知ってがっかりした。', 'ふごうかくと しって がっかり した。', 'Aku kecewa saat tahu tidak lulus.'),
('ex_n3_auto_1751', 'v_n3_auto_1751', '明日は雨が降るかもしれない。', 'あしたは あめが ふる かもしれない。', 'Besok mungkin akan turun hujan.'),
('ex_n3_auto_1752', 'v_n3_auto_1752', '蚊に刺されて腕がかゆい。', 'かに さされて うでが かゆい。', 'Lenganku gatal karena digigit nyamuk.'),
('ex_n3_auto_1753', 'v_n3_auto_1753', 'この靴は少しきついです。', 'この くつは すこし きついです。', 'Sepatu ini agak ketat.'),
('ex_n3_auto_1754', 'v_n3_auto_1754', '昨夜はぐっすり眠れました。', 'さくやは ぐっすり ねむれました。', 'Semalam aku bisa tidur nyenyak.'),
('ex_n3_auto_1755', 'v_n3_auto_1755', '彼は大金持ちなのにけちだ。', 'かれは おおがねもちなのに けちだ。', 'Dia pelit padahal orang yang sangat kaya.'),
('ex_n3_auto_1756', 'v_n3_auto_1756', 'テーブルの上にコーヒーをこぼした。', 'テーブルの うえに コーヒーを こぼした。', 'Aku menumpahkan kopi di atas meja.'),
('ex_n3_auto_1757', 'v_n3_auto_1757', 'コップから水がこぼれた。', 'コップから みずが こぼれた。', 'Air tumpah dari gelas.'),
('ex_n3_auto_1758', 'v_n3_auto_1758', '遅くなってごめんなさい。', 'おそくなって ごめんなさい。', 'Maaf karena saya terlambat.'),
('ex_n3_auto_1759', 'v_n3_auto_1759', 'これらの本はすべて私のです。', 'これらの ほんは すべて わたしのです。', 'Buku-buku ini semuanya milikku.'),
('ex_n3_auto_1760', 'v_n3_auto_1760', 'こんなに美味しい料理は初めてだ。', 'こんなに おいしい りょうりは はじめてだ。', 'Ini pertama kalinya aku makan hidangan seenak ini.'),
('ex_n3_auto_1761', 'v_n3_auto_1761', '皆さん、こんにちは。', 'みなさん、 こんにちは。', 'Halo semuanya, selamat siang.'),
('ex_n3_auto_1762', 'v_n3_auto_1762', '資料にざっと目を通した。', 'しりょうに ざっと めを とおした。', 'Aku membaca sekilas dokumen itu.'),
('ex_n3_auto_1763', 'v_n3_auto_1763', 'シャワーを浴びてさっぱりした。', 'シャワーを あびて さっぱり した。', 'Aku merasa segar setelah mandi.'),
('ex_n3_auto_1764', 'v_n3_auto_1764', 'もしかすると彼は来ないかもしれない。', 'もしかすると かれは こない かもしれない。', 'Barangkali dia tidak akan datang.'),
('ex_n3_auto_1765', 'v_n3_auto_1765', '食べ物を残すのはもったいない。', 'たべものを のこすのは もったいない。', 'Menyisakan makanan itu mubazir.'),
('ex_n3_auto_1766', 'v_n3_auto_1766', '今年の試験は昨年よりやや難しい。', 'ことしの しけんは さくねんより やや むずかしい。', 'Ujian tahun ini agak lebih sulit dibanding tahun lalu.'),
('ex_n3_auto_1767', 'v_n3_auto_1767', '健康は富より大切だ。', 'けんこうは とみより たいせつだ。', 'Keseimbangan kesehatan lebih penting daripada kekayaan.'),
('ex_n3_auto_1768', 'v_n3_auto_1768', 'わがままな行動で皆に迷惑をかけた。', 'わがままな こうどうで みなに めいわくを かけた。', 'Perilaku egoisnya menyusahkan semua orang.'),
('ex_n3_auto_1769', 'v_n3_auto_1769', 'ことによると明日出発するかもしれない。', 'ことによると あした しゅっぱつする かもしれない。', 'Mungkin saja kami akan berangkat besok.'),
('ex_n3_auto_1770', 'v_n3_auto_1770', '雨が降り出した。そこで傘を買った。', 'あめが フリダシタ。 そこで かさを かった。', 'Hujan mulai turun. Oleh karena itu, aku membeli payung.'),
('ex_n3_auto_1771', 'v_n3_auto_1771', '彼は父親にそっくりだ。', 'かれは ちちおやに そっくりだ。', 'Dia mirip sekali dengan ayahnya.'),
('ex_n3_auto_1772', 'v_n3_auto_1772', '片付けずにそのままにしておいて。', 'かたづけずに そのままに しておいて。', 'Biarkan begitu saja tanpa dibereskan.'),
('ex_n3_auto_1773', 'v_n3_auto_1773', '人にはそれぞれ個性がある。', 'ひとには それぞれ こせいがある。', 'Setiap orang memiliki kepribadian masing-masing.'),
('ex_n3_auto_1774', 'v_n3_auto_1774', 'パンと牛乳、それと卵をください。', 'パンと ぎゅうにゅう、 それと たまごを ください。', 'Tolong roti, susu, dan juga telur.'),
('ex_n3_auto_1775', 'v_n3_auto_1775', '彼は努力した。だが、失敗した。', 'かれは どりょくした。 だが、 しっぱいした。', 'Dia sudah berusaha. Namun, dia gagal.'),
('ex_n3_auto_1776', 'v_n3_auto_1776', '行きたい。だけどお金がない。', 'いきたい。 だけど おかねが ない。', 'Aku ingin pergi. Tetapi aku tidak punya uang.'),
('ex_n3_auto_1777', 'v_n3_auto_1777', '彼の住所はたしかここだったはずだ。', 'かれの じゅうしょは たしか ここだった はずだ。', 'Seingat saya, alamatnya seharusnya di sini.'),
('ex_n3_auto_1778', 'v_n3_auto_1778', 'なぜ行かないの？だって忙しいんだもん。', 'なぜ いかないの？ だって いそがしいんだもん。', 'Kenapa tidak pergi? Habisnya sibuk sih.'),
('ex_n3_auto_1779', 'v_n3_auto_1779', '彼とはたびたび駅で会う。', 'かれとは たびたび えきで あう。', 'Aku sering kali bertemu dengannya di stasiun.'),
('ex_n3_auto_1780', 'v_n3_auto_1780', '暑くてたまらない。', 'あつくて たまらない。', 'Panasnya tidak tertahankan.'),
('ex_n3_auto_1781', 'v_n3_auto_1781', 'そのリンゴを一口ちょうだい。', 'その りんごを ひとくち ちょうだい。', 'Tolong beri aku satu gigit apel itu.'),
('ex_n3_auto_1782', 'v_n3_auto_1782', 'できれば今日中に終わらせたい。', 'できれば きょうじゅうに おわらせたい。', 'Kalau bisa aku ingin menyelesaikannya hari ini.'),
('ex_n3_auto_1783', 'v_n3_auto_1783', 'バスが遅れました。ですから遅刻しました。', 'バスが おくれました。 ですから ちこくしました。', 'Busnya terlambat. Oleh karena itu saya terlambat.'),
('ex_n3_auto_1784', 'v_n3_auto_1784', '新しいメンバーです。どうぞよろしく。', 'あたらしい めんばーです。 どうぞ よろしく。', 'Saya anggota baru. Senang bertemu dengan Anda.'),
('ex_n3_auto_1785', 'v_n3_auto_1785', '鍵をどこかに忘れてしまった。', 'かぎを どこかに わすれて しまった。', 'Aku melupakan kunci di suatu tempat.'),
('ex_n3_auto_1786', 'v_n3_auto_1786', '謙遜して「とんでもない」と答えた。', 'けんそんして 「とんでもない」と こたえた。', 'Dia menjawab "sama sekali tidak" dengan rendah hati.'),
('ex_n3_auto_1787', 'v_n3_auto_1787', 'どんなに難しくても諦めない。', 'どんなに むずかしくても あきらめない。', 'Bagaimanapun sulitnya, aku tidak akan menyerah.'),
('ex_n3_auto_1788', 'v_n3_auto_1788', '今日はなにもしたくない。', 'きょうは なにも したくない。', 'Hari ini aku tidak ingin melakukan apa pun.'),
('ex_n3_auto_1789', 'v_n3_auto_1789', '彼女はにっこり笑って挨拶した。', 'かのじょは にっこり わらって あいさつした。', 'Dia tersenyum ramah lalu menyapa.'),
('ex_n3_auto_1790', 'v_n3_auto_1790', '週末はのんびり過ごしたい。', 'しゅうまつは のんびり すごしたい。', 'Aku ingin menghabiskan akhir pekan dengan santai.'),
('ex_n3_auto_1791', 'v_n3_auto_1791', '紙をはさみできれいに切った。', 'かみを はさみで きれいに きった。', 'Aku memotong kertas dengan rapi menggunakan gunting.'),
('ex_n3_auto_1792', 'v_n3_auto_1792', '街中で古い友人にばったり会った。', 'まちなかで ふるい ゆうじんに ばったり あった。', 'Aku tidak sengaja bertemu teman lama di jalan.'),
('ex_n3_auto_1793', 'v_n3_auto_1793', 'この服はサイズがぴったりだ。', 'この ふくは さいずが ぴったりだ。', 'Ukuran baju ini pas sekali.'),
('ex_n3_auto_1794', 'v_n3_auto_1794', '自転車が電柱にぶつかった。', 'じてんしゃが でんちゅうに ぶつかった。', 'Sepeda menabrak tiang listrik.'),
('ex_n3_auto_1795', 'v_n3_auto_1795', '車を壁にぶつけてしまった。', 'くるまを かべに ぶつけて しまった。', 'Aku tidak sengaja menabrakkan mobil ke dinding.'),
('ex_n3_auto_1796', 'v_n3_auto_1796', 'まあ、なんてきれいな花でしょう。', 'まあ、 なんて きれいな はなでしょう。', 'Ya ampun, alangkah indahnya bunga ini.'),
('ex_n3_auto_1797', 'v_n3_auto_1797', 'これこそがまさに私が探していた本だ。', 'これこそが まさに わたしが さがしていた ほんだ。', 'Buku inilah yang benar-benar kucari.'),
('ex_n3_auto_1798', 'v_n3_auto_1798', '朝の太陽がまぶしい。', 'あさの たいようが まぶしい。', 'Matahari pagi sangat silau.'),
('ex_n3_auto_1799', 'v_n3_auto_1799', '友達と図書館へ行った。', 'ともだちと としょかんへ いった。', 'Aku pergi ke perpustakaan dengan teman.'),
('ex_n3_auto_1800', 'v_n3_auto_1800', '試験が終わってほっとした。', 'しけんが おわって ほっと した。', 'Aku merasa lega setelah ujian selesai.'),
('ex_n3_auto_1801', 'v_n3_auto_1801', '新しい青いジーンズを買った。', 'あたらしい あおい ジーンズを かった。', 'Aku membeli celana jin biru baru.'),
('ex_n3_auto_1802', 'v_n3_auto_1802', '部屋の電気のスイッチを押した。', 'へやの でんきの スイッチを おした。', 'Aku menekan sakelar lampu kamar.'),
('ex_n3_auto_1803', 'v_n3_auto_1803', '温かい野菜スープを作った。', 'あたたかい やさい スープを つくった。', 'Aku membuat sup sayur hangat.'),
('ex_n3_auto_1804', 'v_n3_auto_1804', '冬に湖でスケートをする。', 'ふゆに みずうみで スケートを する。', 'Bermain seluncur es di danau saat musim dingin.'),
('ex_n3_auto_1805', 'v_n3_auto_1805', '彼は映画界の人気スターだ。', 'かれは えいがかいの にんき スターだ。', 'Dia adalah bintang populer di dunia perfilman.'),
('ex_n3_auto_1806', 'v_n3_auto_1806', '彼女はスタイルがとても良い。', 'かのじょは スタイルが とても いい。', 'Dia memiliki bentuk tubuh yang sangat bagus.'),
('ex_n3_auto_1807', 'v_n3_auto_1807', '机の上に電気スタンドを置く。', 'つくえの うえに でんき スタンドを おく。', 'Meletakkan lampu meja di atas meja belajar.'),
('ex_n3_auto_1808', 'v_n3_auto_1808', '大勢の前でスピーチをした。', 'おおぜいの まえで スピーチを した。', 'Aku berpidato di depan banyak orang.'),
('ex_n3_auto_1809', 'v_n3_auto_1809', 'ハンバーガーのセットを注文した。', 'ハンバーガーの セットを ちゅうもんした。', 'Aku memesan paket hamburger set.'),
('ex_n3_auto_1810', 'v_n3_auto_1810', '暑い日はアイスクリームが食べたい。', 'あつい ひは アイスクリームが たべたい。', 'Aku ingin makan es krim di hari yang panas.'),
('ex_n3_auto_1811', 'v_n3_auto_1811', 'ボールがラインの外に出てアウトになった。', 'ボールが ラインの そとに でて アウトに なった。', 'Bola keluar garis dan dinyatakan keluar.'),
('ex_n3_auto_1812', 'v_n3_auto_1812', '家族の写真アルバムを眺める。', 'かぞくの しゃしん アルバムを ながめる。', 'Memandangi album foto keluarga.'),
('ex_n3_auto_1813', 'v_n3_auto_1813', '新しいデザインのイメージを描く。', 'あたらしい デザインの イメージを えがく。', 'Menggambar bayangan desain baru.'),
('ex_n3_auto_1814', 'v_n3_auto_1814', 'プリンターのインクが切れた。', 'プリンターの インクが きれた。', 'Tinta printer habis.'),
('ex_n3_auto_1815', 'v_n3_auto_1815', '有名な作家にインタビューする。', 'ゆうめいな さっかに インタビュー する。', 'Mewawancarai penulis terkenal.'),
('ex_n3_auto_1816', 'v_n3_auto_1816', '彼はロックでウイスキーを飲む。', 'かれは ロックで ウイスキーを のむ。', 'Dia meminum wiski dengan es batu.'),
('ex_n3_auto_1817', 'v_n3_auto_1817', '車のエンジンがかからない。', 'くるまの エンジンが かからない。', 'Mesin mobil tidak mau menyala.'),
('ex_n3_auto_1818', 'v_n3_auto_1818', '東京のオフィスで働いている。', 'とうきょうの オフィスで はたらいている。', 'Aku bekerja di kantor Tokyo.'),
('ex_n3_auto_1819', 'v_n3_auto_1819', 'パトロールカーが通り過ぎた。', 'パトロールカーが とおりすぎた。', 'Mobil patroli lewat.'),
('ex_n3_auto_1820', 'v_n3_auto_1820', 'クレジットカードで支払う。', 'クレジットカードで しはらう。', 'Membayar dengan kartu kredit.'),
('ex_n3_auto_1821', 'v_n3_auto_1821', '彼がサッカーチームのキャプテンだ。', 'かれが サッカーチームの キャプテンだ。', 'Dialah kapten tim sepak bola.'),
('ex_n3_auto_1822', 'v_n3_auto_1822', '勉強するときはクラシックを聴く。', 'べんきょうする ときは クラシックを きく。', 'Mendengarkan musik klasik saat belajar.'),
('ex_n3_auto_1823', 'v_n3_auto_1823', '冷たい水をグラスに注いだ。', 'つめたい みずを グラスに そそいだ。', 'Menuangkan air dingin ke dalam gelas.'),
('ex_n3_auto_1824', 'v_n3_auto_1824', '放課後に学校のグランドで走る。', 'ほうかごに がっこうの グランドで はしる。', 'Berlari di lapangan sekolah setelah pulang sekolah.'),
('ex_n3_auto_1825', 'v_n3_auto_1825', 'ケーキの上に生クリームをのせる。', 'ケーキの うえに なまクリームを のせる。', 'Menaruh krim segar di atas kue.'),
('ex_n3_auto_1826', 'v_n3_auto_1826', '４人のグループで旅行をする。', 'よにんの グループで りょこうを する。', 'Melakukan perjalanan dalam kelompok yang terdiri dari 4 orang.'),
